class Codec:

    def encode(self, longUrl: str) -> str:
        import hashlib
        hash_object = hashlib.md5(longUrl.encode())
        return "http://tinyurl.com/" + hash_object.hexdigest()

    def decode(self, shortUrl: str) -> str:
        import hashlib
        hash_object = hashlib.md5(shortUrl.split("http://tinyurl.com/")[-1])
        return hash_object.hexdigest()
